document.addEventListener("DOMContentLoaded",(function(){const t=document.querySelectorAll(".percentTotal");function parseEL(t){if(null==t)return 0;let e=String(t).trim();if(!e)return 0;e=e.replace(/\s/g,"");const n=e.includes(","),r=e.includes(".");if(n&&r){const t=e.lastIndexOf(","),n=e.lastIndexOf(".");e=t>n?e.replace(/\./g,"").replace(",","."):e.replace(/,/g,"")}else if(n){const t=e.split(",");e=t.length>2?t.slice(0,-1).join("")+"."+t.at(-1):e.replace(",",".")}else if(r){const t=e.split(".");e=t.length>2?t.slice(0,-1).join("")+"."+t.at(-1):e}const o=Number(e);return Number.isFinite(o)?o:0}const formatEL=t=>Number(t).toLocaleString("el-GR",{minimumFractionDigits:2,maximumFractionDigits:2,useGrouping:!1});function checkTotal(){const e=Array.from(t).reduce(((t,e)=>t+parseEL(e.value)),0),n=Number(e.toFixed(2));n>100&&Swal.fire({icon:"warning",title:"Λάθος Σύνολο Ποσοστών",html:`Το σύνολο των ποσοστών <strong>${formatEL(n)}%</strong> δεν μπορεί να είναι μεγαλύτερο του <strong>100,00%</strong>`,confirmButtonText:"Κλείσιμο",focusConfirm:!0,allowOutsideClick:!1,backdrop:!1,customClass:{confirmButton:"class-warning custom-confirm-button custom-swal-button",title:"custom-title",popup:"custom-swal-popup"}})}t.forEach((t=>{t.addEventListener("input",checkTotal),t.addEventListener("blur",(t=>{const e=parseEL(t.target.value);t.target.value=e?formatEL(e):"","number"===t.target.type&&t.target.value.includes(",")&&(t.target.type="text")})),t.addEventListener("focus",(t=>{const e=parseEL(t.target.value);t.target.type="number",t.target.value=e?String(e):""}))}))}));